        "1010": {
          "header": "1010",
          "lines": [
            "GrdTlk 35,8,sdChoc1",
            "That's not what you told the passport officer at the airport!!!"
          ]
        },
        "1020": {
          "header": "1020",
          "lines": [
            "GrdTlk 35,8,sdChoc2",
            "All visitors need ID cards."
          ]
        },
        "1030": {
          "header": "1030",
          "lines": [
            "GrdTlk 35,8,sdChoc3",
            "May I see your ID, please?"
          ]
        },
        "1040": {
          "header": "1040",
          "lines": [
            "GrdTlk 35,8,sdChoc4",
            "Thank you, young man.  You can go in.  But don't eat the chocolate.  It doesn't taste very good!"
          ]
        },
        "1050": {
          "header": "1050",
          "lines": [
            "ChldTlk 39,20,sdChld1",
            "Share my bubble gum? You must be joking!  It's my last piece!"
          ]
        },
        "1060": {
          "header": "1060",
          "lines": [
            "ChldTlk 39,20,sdChld2",
            "Sorry, there are no kids called Brad and Urma on Palm Island."
          ]
        },
        "1070": {
          "header": "1070",
          "lines": [
            "ChldTlk 39,20,sdChld3",
            "I think you should take another look at your information."
          ]
        }
