      "messages": {
        "1010": {
          "header": "1010",
          "lines": [
            "TckTlk 40,17,sdTckt1",
            "Do you have a coupon?  It's cheaper that way."
          ]
        },
        "1020": {
          "header": "1020",
          "lines": [
            "TckTlk 40,17,sdTckt2",
            "Here is your ticket.  Hold on to it! That will be 50 Palmettoes."
          ]
        },
        "1030": {
          "header": "1030",
          "lines": [
            "TckTlk 40,17,sdTckt3",
            "What do you want? Speak up, young man!"
          ]
        },
        "1040": {
          "header": "1040",
          "lines": [
            "TckTlk 40,17,sdTckt4",
            "What do you want?  You already bought a ticket!"
          ]
        },
        "1050": {
          "header": "1050",
          "lines": [
            "GranTlk 43,22,sdEmpl12",
            "What do you mean - you don't have time?  I thought you were on holiday!"
          ]
        },
        "1060": {
          "header": "1060",
          "lines": [
            "GranTlk 43,22,sdEmpl13",
            "You should have some fun. All work and no play will make you a dull boy!"
          ]
        },
        "1070": {
          "header": "1070",
          "lines": [
            "GranTlk 43,22,sdEmpl14",
            "Grandma Rosy?  Sorry, there is no one by that name on Palm Island."
          ]
        },
        "1080": {
          "header": "1080",
          "lines": [
            "GranTlk 43,22,sdEmpl15",
            "I think you should take another look at your information."
          ]
        },
        "1090": {
          "header": "1090",
          "lines": [
            "GranTlk 43,22,sdEmpl16",
            "Look with your eyes - not with your hands!"
          ]
        }
      },
